                                 .review-section{
                                       max-width:850px;
                                       margin:30px auto;
                                       display:flex;
                                       flex-direction:column;
                                       gap:18px;
                                       font-family:system-ui,Arial,sans-serif;
                                 }
                                 .review-card{
                                       background:#f5f5f5;
                                       padding:16px 20px;
                                       border-radius:10px;
                                       border-left:5px solid var(--brand);
                                       box-shadow:0 3px 6px rgba(0,0,0,.05);
                                       transition:all .25s ease-in-out;
                                 }
                                 .review-card:hover{
                                       transform:translateY(-3px);
                                       box-shadow:0 5px 10px rgba(0,0,0,.08);
                                 }
                                 .review-author{
                                       font-weight:700;
                                       color:var(--brand-dark);
                                       margin-bottom:4px;
                                       display:flex;
                                       align-items:center;
                                       gap:6px;
                                       font-size:.96rem; /* naik sedikit */
                                 }
                                 .review-author::before{
                                       content:"";
                                       font-size:1rem;
                                 }
                                 .review-card p{
                                       margin:0;
                                       color:#222;
                                       font-size:.98rem; /* naik sedikit */
                                       line-height:1.6;
                                 }
                                 .review-rating{
                                       margin-left:auto;
                                       font-weight:700;
                                 }

                                 .stars{
                                       --rating:5;
                                       --star-size:1rem;
                                       --star-gap:2px;
                                       --star-empty:#e5e7eb;
                                       --star-fill:#ff3030; /* hijau -> merah */
                                       position:relative;
                                       display:inline-block;
                                       font-size:var(--star-size);
                                       line-height:1;
                                       letter-spacing:var(--star-gap);
                                 }
                                 .stars::before{
                                       content:"★★★★";
                                       color:var(--star-empty);
                                 }
                                 .stars::after{
                                       content:"★★★★★";
                                       color:var(--star-fill);
                                       position:absolute;
                                       left:0;
                                       top:0;
                                       width:calc((var(--rating)/5)*100%);
                                       overflow:hidden;
                                       white-space:nowrap;
                                       pointer-events:none;
                                 }
                                 .stars.lg{
                                       --star-size:1.15rem; /* naik sedikit */
                                       letter-spacing:3px;
                                 }
                                 .badge{
                                       display:inline-flex;
                                       align-items:center;
                                       gap:8px;
