   <script>
(() => {
  const COUNT = 35; // reduced for performance
  const FIREWORK_INTERVAL = 2200;

  const wrap = document.createElement("div");
  wrap.id = "fx-overlay";
  wrap.setAttribute("aria-hidden", "true");
  document.body.appendChild(wrap);

  const fragment = document.createDocumentFragment();

  function random(min, max) {
    return Math.random() * (max - min) + min;
  }

  function createFlake() {
    const el = document.createElement("span");
    el.className = "fx-flake";

    const sizeClass =
      Math.random() < 0.25 ? "fx-sm" :
      Math.random() > 0.8 ? "fx-lg" : "fx-md";

    el.classList.add(sizeClass);

    el.style.left = random(0, 100) + "%";
    el.style.setProperty("--dur", random(10, 20) + "s");
    el.style.setProperty("--delay", random(0, 8) + "s");
    el.style.setProperty("--drift", random(-30, 30) + "px");
    el.style.setProperty("--rot", random(0, 360) + "deg");
    el.style.setProperty("--sway", random(4, 8) + "s");

    return el;
  }

  function initSnow() {
    for (let i = 0; i < COUNT; i++) {
      fragment.appendChild(createFlake());
    }
    wrap.appendChild(fragment);
  }

  function spawnFirework() {
    const fw = document.createElement("span");
    fw.className = "fx-firework";

    fw.style.left = random(10, 90) + "%";
    fw.style.top = random(10, 40) + "%";

    wrap.appendChild(fw);
    setTimeout(() => fw.remove(), 1800);
  }

  let fireworkTimer;

  function startFireworks() {
    spawnFirework();
    fireworkTimer = setInterval(spawnFirework, FIREWORK_INTERVAL);
  }

  function stopFireworks() {
    clearInterval(fireworkTimer);
  }

  document.addEventListener("visibilitychange", () => {
    if (document.hidden) {
      stopFireworks();
    } else {
      startFireworks();
    }
  });

  initSnow();
  startFireworks();
})();
</script>
